def numOfIncSubseqOfSizeK(arr, n, k):
    # Initialize a 2D list with k rows and n columns, all zeros
    dp = [[0] * n for _ in range(k)]
    # Base case: every single element is an increasing subsequence of length 1
    for i in range(n):
        dp[0][i] = 1
    # Fill dp for lengths from 1 to k-1
    for l in range(1, k):
        for i in range(l, n):
            dp[l][i] = 0
            for j in range(l - 1, i):
                if arr[j] < arr[i]:
                    dp[l][i] += dp[l-1][j]
    # Sum the last row (subsequences of length k ending at each position)
    total = 0
    for i in range(k - 1, n):
        total += dp[k-1][i]
    return total

