def gcd(a, b):
    if a == b:
        return a
    if a == 0:
        return b
    if b == 0:
        return a
    # Check if 'a' is even
    if (a & 1) == 0:
        # Check if 'b' is odd
        if (b & 1) == 1:
            return gcd(a >> 1, b)
        else:
            return gcd(a >> 1, b >> 1) << 1
    # Check if 'b' is even (since 'a' is odd)
    if (b & 1) == 0:
        return gcd(a, b >> 1)
    # Both are odd
    if a > b:
        return gcd((a - b) >> 1, b)
    else:
        return gcd((b - a) >> 1, a)

